<div class="page-title-row"><div><span class="text-muted">Leadership reporting</span><h1>Scheduled Executive Reports</h1></div></div><div class="row g-4"><div class="col-lg-4"><div class="portal-card p-4"><h2>Create schedule</h2><form method="post" action="/portal/executive-reports" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Name</label><input class="form-control" name="name" required></div><div class="col-12"><label class="form-label">Report</label><select class="form-select" name="report_key"><option value="executive_summary">Executive summary</option><option value="financial">Financial performance</option><option value="operations">Operations & productivity</option><option value="collections">Collections</option></select></div><div class="col-6"><label class="form-label">Frequency</label><select class="form-select" name="frequency"><option>daily</option><option selected>weekly</option><option>monthly</option></select></div><div class="col-6"><label class="form-label">Send time</label><input class="form-control" type="time" name="send_time" value="07:00"></div><div class="col-6"><label class="form-label">Day of week</label><input class="form-control" type="number" min="0" max="6" name="day_of_week" placeholder="1 = Monday"></div><div class="col-6"><label class="form-label">Day of month</label><input class="form-control" type="number" min="1" max="28" name="day_of_month"></div><div class="col-12"><label class="form-label">Recipients</label><textarea class="form-control" name="recipients" placeholder="owner@rockbluffs.com, office@rockbluffs.com" required></textarea></div><div class="col-12"><label class="form-check"><input class="form-check-input" type="checkbox" name="include_pdf" checked> Attach PDF</label><label class="form-check"><input class="form-check-input" type="checkbox" name="active" checked> Active</label></div><div class="col-12"><button class="btn btn-primary">Create schedule</button></div></form></div></div><div class="col-lg-8"><div class="portal-card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Name</th><th>Report</th><th>Frequency</th><th>Recipients</th><th>Next run</th><th>Status</th></tr></thead><tbody><?php foreach($schedules as $s):?><tr><td><?=e($s['name'])?></td><td><?=e($s['report_key'])?></td><td><?=e($s['frequency'])?></td><td><?=e($s['recipients'])?></td><td><?=e($s['next_run_at'])?></td><td><?=$s['active']?'<span class="badge text-bg-success">Active</span>':'<span class="badge text-bg-secondary">Paused</span>'?></td></tr><?php endforeach?></tbody></table></div></div><div class="portal-card mt-4"><div class="card-header-row"><div><h2>Recent deliveries</h2></div></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Report</th><th>Period</th><th>Recipients</th><th>Status</th><th>Sent</th></tr></thead><tbody><?php foreach($runs as $r):?><tr><td><?=e($r['report_key'])?></td><td><?=e($r['period_start'].' – '.$r['period_end'])?></td><td><?=e($r['recipients'])?></td><td><?=e($r['status'])?></td><td><?=e($r['sent_at'])?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
